export const NEGOCIACOES: Negociacao[] = NROWS.map(
  ([id, nome, telefone, origem, et, valorMensal, dataOrigem, dataFechamento, propostaEnviada, proximaAcao]) => {
    const [etapa, temperatura] = et.split("|") as [EtapaVenda, Temperatura];
    return { id, nome, telefone, origem, etapa, temperatura, valorMensal, dataOrigem, dataFechamento, propostaEnviada, proximaAcao };
  },
);

export const ORIGENS: string[] = POR_ORIGEM.map((o) => o.origem);

export const soma = <T extends { valorMensal: number }>(a: T[]) => a.reduce((s, x) => s + x.valorMensal, 0);

export const fmtBRL = (n: number) =>
  n.toLocaleString("pt-BR", { style: "currency", currency: "BRL", maximumFractionDigits: 0 });

export const fmtData = (iso: string) =>
  iso ? new Date(iso + "T12:00:00").toLocaleDateString("pt-BR", { day: "2-digit", month: "short" }) : "—";

const MESES_LABEL: Record<string, string> = {
  "01": "jan", "02": "fev", "03": "mar", "04": "abr", "05": "mai", "06": "jun",
  "07": "jul", "08": "ago", "09": "set", "10": "out", "11": "nov", "12": "dez",
};
export const fmtMesAno = (ym: string) => {
  const [y, m] = ym.split("-");
  return `${MESES_LABEL[m] ?? m}/${y.slice(2)}`;
};
